noncompliant:
class Base {
public:
    virtual void method() {}
};

// Noncompliant - implicit private inheritance
class Derived : Base { // Missing access specifier
public:
    void method() override {}
};

class AnotherDerived : Base, OtherBase { // Noncompliant - implicit private
public:
    void someMethod() {}
};

compliant:
class Base {
public:
    virtual void method() {}
};

// Compliant - explicit access specification
class Derived : public Base { // Explicit public inheritance
public:
    void method() override {}
};

// Compliant - explicit private inheritance when intentional
class PrivateDerived : private Base { // Intentional private inheritance
public:
    void exposedMethod() {}
};
